import Home from './pages/Home';
import Game from './pages/Game';

export const pages = [
  {
    key: 0,
    path: "/",
    element: <Home />
  },
  {
    key: 1,
    path: "/game",
    element: <Game />
  }
];

export const gamePics = [
  [
    { src: "./pics/sparkle_game_0.webp", title: "", description: "" },
